/**
 * Represents a typography token - the leaf nodes in the text token structure.
 * All text tokens have this exact shape with these seven properties.
 */
export interface TypographyToken {
  fontFamily: string;
  fontSize: string;
  fontWeight: string;
  letterSpacing: string;
  lineHeight: string;
  textDecoration: string;
  textTransform: string;
}
